proof_block:
// `SingleDelivery::send_single_message(pre, post, m, dst, sm, params)` is a
// fully deterministic `open spec(checked)`:
//
//   let old_ack_state = ack_state_lookup(dst, pre.send_state);
//   let new_seqno     = old_ack_state.num_packets_acked
//                     + old_ack_state.un_acked.len() + 1;
//   if new_seqno > params.max_seqno {
//       &&& post == pre
//       &&& sm is None
//   } else {
//       &&& sm == Some(SingleMessage::<MT>::Message{ seqno: new_seqno, m, dst })
//       &&& post == SingleDelivery{ send_state: pre.send_state.insert(dst, ...), ..pre }
//   }
//
// Both ensures-conjuncts share `(pre_self_@, m@, dst@, params)`, so the
// if/else condition `new_seqno > params.max_seqno` is the *same* expression
// in both runs.  z3 returned `unknown` because the two `SingleDelivery::
// send_single_message(...)` calls are unfolded on disjoint `(post,sm)`
// chains and the case-split never gets aligned across r1/r2.  We close the
// gap by re-stating each alignment as an implication that Verus must check;
// every line below is unconditionally provable from the open-spec body.

let pre_v   = pre_self_@;
let post1_v = post1_self_@;
let post2_v = post2_self_@;
let params  = AbstractParameters::static_params();

// (A) A Some/None mismatch across the two runs is contradictory: a `Some`
//     witness forces `new_seqno <= max_seqno` (else-branch), while a `None`
//     witness forces `new_seqno >  max_seqno` (then-branch), and the
//     condition is computed from the shared `(pre_v, dst@)`.
assert(
    r1 is Some && r2 is None
    && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, Some(r1->Some_0@), params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, None, params)
    ==> false
);
assert(
    r1 is None && r2 is Some
    && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, None, params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, Some(r2->Some_0@), params)
    ==> false
);

// (B) Both runs `Some`: both land in the else-branch, pinning the
//     `SingleMessage::Message{ seqno: new_seqno, m: m@, dst: dst@ }` witness
//     and the `SingleDelivery` view to identical `pre_v`-derived expressions.
assert(
    r1 is Some && r2 is Some
    && SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, Some(r1->Some_0@), params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, Some(r2->Some_0@), params)
    ==> r1->Some_0@ == r2->Some_0@ && post1_v == post2_v
);

// (C) Both runs `None`: both land in the then-branch, so
//     `post1_v == pre_v == post2_v`.
assert(
    SingleDelivery::send_single_message(pre_v, post1_v, m@, dst@, None, params)
    && SingleDelivery::send_single_message(pre_v, post2_v, m@, dst@, None, params)
    ==> post1_v == post2_v
);

// (D) `SingleDelivery<MT>` carries `#[verifier::ext_equal]`, so its `==`
//     unfolds to per-component equality on the `receive_state`/`send_state`
//     view, which is what `CSingleDelivery::view()` projects onto each
//     concrete field's `view()`.
assert(
    post1_v == post2_v
    ==> post1_self_.receive_state@ == post2_self_.receive_state@
        && post1_self_.send_state@  == post2_self_.send_state@
);

// (E) Push the view equality through the `map_values` wrapper used by
//     `CTombstoneTable::view` / `CSendState::view` so the underlying
//     `epmap@: Map<AbstractEndPoint, _>` views are themselves equal.
assert(
    post1_self_.receive_state@ == post2_self_.receive_state@
    ==> post1_self_.receive_state.epmap@.map_values(|v: u64| v as nat)
        =~= post2_self_.receive_state.epmap@.map_values(|v: u64| v as nat)
);
assert(
    post1_self_.send_state@ == post2_self_.send_state@
    ==> post1_self_.send_state.epmap@.map_values(|v: CAckState| v@)
        =~= post2_self_.send_state.epmap@.map_values(|v: CAckState| v@)
);
